Following up with Mem0 team here: https://github.com/mem0ai/mem0/issues/3215

@lucasgomide

This PR unblocks agent regression testing

Here's an usage example

```python
from crewai.experimental.evaluation.testing import run_experiment, assert_experiment_successfully
from crewai import Crew

def crew():
    ...
    return Crew()

def create_test_dataset():
    dataset = [
        {
            "inputs": {"company": "Apple Inc. (AAPL)"},
            "expected_score": {"tool_selection": 2, "goal_alignment": 2},
        },
        {
            "identifier": "test_2",
            "inputs": {"company": "Microsoft Corporation (MSFT)"},
            "expected_score": 8
        }
    ]
    return dataset



def test_financial_analysis_regression():
    crew = crew()
    dataset = create_test_dataset()

    results = run_experiment(dataset=dataset, crew=crew, verbose=True)

    assert_experiment_successfully(results)

```

